import os

app = Flask(__name__)

DB_CONFIG = {
    'host': os.getenv('DB_HOST', 'localhost'),
    'port': os.getenv('DB_PORT', '5432'),
    'database': os.getenv('DB_NAME', 'analytics_db'),
    'user': os.getenv('DB_USER', 'postgres'),
    'password': os.getenv('DB_PASSWORD', 'password')
}

ALLOWED_TABLES = os.getenv('ALLOWED_TABLES', 'users,orders,products,transactions,analytics').split(',')
MAX_RESULTS = int(os.getenv('MAX_RESULTS', '1000'))

ALLOWED_OPERATORS = {
    'eq': '=',
    'ne': '!=',
    'gt': '>',
    'gte': '>=',
    'lt': '<',
    'lte': '<=',
    'like': 'LIKE',
    'ilike': 'ILIKE',
    'in': 'IN',
    'not_in': 'NOT IN',
    'is_null': 'IS NULL',
    'is_not_null': 'IS NOT NULL'
}

def get_db_connection():
    return psycopg2.connect(**DB_CONFIG)

def validate_identifier(identifier):
    if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', identifier):
        raise ValueError(f"Invalid identifier: {identifier}")
    return identifier

def validate_table_name(table_name):
    validate_identifier(table_name)
    if table_name not in ALLOWED_TABLES:
        raise ValueError(f"Table '{table_name}' is not allowed")
    return table_name

def handle_errors(f):
    @wraps(f)
    def wrapper(*args, **kwargs):
        try:
            return f(*args, **kwargs)
        except ValueError as e:
            return jsonify({'error': 'Validation Error', 'message': str(e)}), 400
        except psycopg2.Error as e:
            return jsonify({'error': 'Database Error', 'message': str(e)}), 500
        except Exception as e:
            return jsonify({'error': 'Internal Server Error', 'message': str(e)}), 500
    return wrapper

def build_where_clause(filters):
    if not filters:
        return sql.SQL(""), []
    
    conditions = []
    params = []
    
    for filter_item in filters:
        column = validate_identifier(filter_item.get('column'))
        operator = filter_item.get('operator', 'eq')
        value = filter_item.get('value')
        
        if operator not in ALLOWED_OPERATORS:
            raise ValueError(f"Invalid operator: {operator}")
        
        sql_operator = ALLOWED_OPERATORS[operator]
        
        if operator in ['is_null', 'is_not_null']:
            conditions.append(
                sql.SQL("{} {}").format(
                    sql.Identifier(column),
                    sql.SQL(sql_operator)
                )
            )
        elif operator in ['in', 'not_in']:
            if not isinstance(value, list):
                raise ValueError(f"Value for {operator} must be a list")
            placeholders = sql.SQL(', ').join([sql.Placeholder()] * len(value))
            conditions.append(
                sql.SQL("{} {} ({})").format(
                    sql.Identifier(column),
                    sql.SQL(sql_operator),
                    placeholders
                )
            )
            params.extend(value)
        else:
            conditions.append(
                sql.SQL("{} {} {}").format(
                    sql.Identifier(column),
                    sql.SQL(sql_operator),
                    sql.Placeholder()
                )
            )
            params.append(value)
    
    where_clause = sql.SQL(" WHERE ") + sql.SQL(" AND ").join(conditions)
    return where_clause, params

def build_order_clause(order_by):
    if not order_by:
        return sql.SQL("")
    
    order_parts = []
    for order_item in order_by:
        column = validate_identifier(order_item.get('column'))
        direction = order_item.get('direction', 'ASC').upper()
        
        if direction not in ['ASC', 'DESC']:
            raise ValueError(f"Invalid sort direction: {direction}")
        
        order_parts.append(
            sql.SQL("{} {}").format(
                sql.Identifier(column),
                sql.SQL(direction)
            )
        )
    
    return sql.SQL(" ORDER BY ") + sql.SQL(", ").join(order_parts)

def build_join_clause(joins):
    if not joins:
        return sql.SQL("")
    
    join_parts = []
    for join_item in joins:
        join_table = validate_table_name(join_item.get('table'))
        join_type = join_item.get('type', 'INNER').upper()
        on_condition = join_item.get('on')
        
        if join_type not in ['INNER', 'LEFT', 'RIGHT', 'FULL']:
            raise ValueError(f"Invalid join type: {join_type}")
        
        left_column = validate_identifier(on_condition.get('left_column'))
        right_column = validate_identifier(on_condition.get('right_column'))
        left_table = on_condition.get('left_table')
        right_table = on_condition.get('right_table', join_table)
        
        if left_table:
            validate_identifier(left_table)
            left_qual = sql.SQL("{}.{}").format(sql.Identifier(left_table), sql.Identifier(left_column))
        else:
            left_qual = sql.Identifier(left_column)
        
        validate_identifier(right_table)
        right_qual = sql.SQL("{}.{}").format(sql.Identifier(right_table), sql.Identifier(right_column))
        
        join_parts.append(
            sql.SQL(" {} JOIN {} ON {} = {}").format(
                sql.SQL(join_type),
                sql.Identifier(join_table),
                left_qual,
                right_qual
            )
        )
    
    return sql.SQL("").join(join_parts)

@app.route('/api/query', methods=['POST'])
@handle_errors
def dynamic_query():
    data = request.get_json()
    
    if not data:
        return jsonify({'error': 'No data provided'}), 400
    
    table_name = validate_table_name(data.get('table'))
    columns = data.get('columns', ['*'])
    filters = data.get('filters', [])
    order_by = data.get('order_by', [])
    joins = data.get('joins', [])
    limit = min(data.get('limit', 100), MAX_RESULTS)
    offset = data.get('offset', 0)
    
    if columns != ['*']:
        column_parts = []
        for col in columns:
            if isinstance(col, dict):
                column_name = validate_identifier(col.get('name'))
                alias = col.get('alias')
                table_prefix = col.get('table')
                
                if table_prefix:
                    validate_identifier(table_prefix)
                    col_sql = sql.SQL("{}.{}").format(
                        sql.Identifier(table_prefix),
                        sql.Identifier(column_name)
                    )
                else:
                    col_sql = sql.Identifier(column_name)
                
                if alias:
                    validate_identifier(alias)
                    col_sql = sql.SQL("{} AS {}").format(col_sql, sql.Identifier(alias))
                
                column_parts.append(col_sql)
            else:
                validate_identifier(col)
                column_parts.append(sql.Identifier(col))
        
        select_clause = sql.SQL(", ").join(column_parts)
    else:
        select_clause = sql.SQL("*")
    
    where_clause, params = build_where_clause(filters)
    order_clause = build_order_clause(order_by)
    join_clause = build_join_clause(joins)
    
    query = sql.SQL("SELECT {} FROM {}{}{}{}").format(
        select_clause,
        sql.Identifier(table_name),
        join_clause,
        where_clause,
        order_clause
    )
    
    if limit:
        query = sql.SQL("{} LIMIT {}").format(query, sql.Literal(limit))
    
    if offset:
        query = sql.SQL("{} OFFSET {}").format(query, sql.Literal(offset))
    
    conn = get_db_connection()
    try:
        with conn.cursor(cursor_factory=extras.RealDictCursor) as cursor:
            cursor.execute(query, params)
            results = cursor.fetchall()
            
            return jsonify({
                'success': True,
                'count': len(results),
                'data': results
            })
    finally:
        conn.close()

